SELECT 
FROM learning_cockpit_rank_snapshot
WHERE user_id = #{userId}
  AND week_start = #{weekStart}
LIMIT 1

SELECT 
FROM learning_cockpit_rank_snapshot
WHERE user_id = #{userId}
  AND week_start < #{weekStart}
ORDER BY week_start DESC
LIMIT 1

SELECT 
FROM learning_cockpit_rank_snapshot
WHERE user_id = #{userId}
ORDER BY week_start DESC
LIMIT #{limit}
